import { MedicalClaimsPage } from '@/components/claims/medical-claims-page';

export default function BenefitsPage() {
  return (
    <PageLayout module="benefits">
      <MedicalClaimsPage />
    </PageLayout>
  );
}

'use client';

import { useState, useEffect, useCallback } from 'react';

// --- Types ---

export type DiseaseCategory =
  | 'general'
  | 'dental'
  | 'vision'
  | 'maternity'
  | 'accident'
  | 'chronic'
  | 'mental_health'
  | 'other';

export type MedicalClaimStatus =
  | 'draft'
  | 'submitted'
  | 'pending_manager'
  | 'pending_hr'
  | 'processing'
  | 'approved'
  | 'rejected';

export interface ClaimDocument {
  id: string;
  type: 'receipt' | 'medical_cert' | 'other';
  fileName: string;
  fileSize: number;
  uploadedAt: string;
}

export interface ApprovalStep {
  step: number;
  role: string;
  approverName: string;
  status: 'pending' | 'approved' | 'rejected';
  date: string | null;
  comment: string | null;
}

export interface MedicalClaim {
  id: string;
  diseaseCategory: DiseaseCategory;
  diseaseDetails: string;
  hospitalName: string;
  treatmentDate: string;
  receiptAmount: number;
  claimAmount: number;
  remarks: string;
  documents: ClaimDocument[];
  approvalSteps: ApprovalStep[];
  status: MedicalClaimStatus;
  submittedAt: string | null;
  approvedAt: string | null;
  rejectionReason: string | null;
  rejectedAt: string | null;
  createdAt: string;
  updatedAt: string;
}

export interface MedicalBenefitSummary {
  planType: string;
  annualLimit: number;
  usedAmount: number;
  remainingAmount: number;
}

// --- Constants ---

