const { chromium } = require('playwright');
(async () => {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage();

  // Intercept CSS responses
  let darkFound = false;
  page.on('response', async (response) => {
    if (response.url().includes('.css') || response.headers()['content-type']?.includes('text/css')) {
      try {
        const text = await response.text();
        if (text.includes('dark:') || text.includes('.dark')) {
          const darkMatches = text.match(/\.dark[^{]+\{[^}]+\}/g);
          if (darkMatches) {
            console.log('Dark CSS rules found:', darkMatches.slice(0, 3).join('\n'));
            darkFound = true;
          }
        }
      } catch(e) {}
    }
  });

  await page.goto('http://localhost:3000', { waitUntil: 'networkidle' });
  if (!darkFound) console.log('No .dark CSS rules found in served CSS');
  await browser.close();
})();
" 2>&1 | head -30

