/* ════════════════════════════════════════════════════════════════════════
   Blueprint rail + panel shell nav (bp-shellnav / bp-rail / bp-panel) —
   two-column master-detail (wireframe 2026-05-25). Col1 = macro-group icon
   rail; Col2 = leaves of the selected group. Overrides the base .humi-sidebar
   column layout to a row of [rail | panel]. Supersedes the bp-nav* accordion
   rules above (now unused).
   ════════════════════════════════════════════════════════════════════════ */
.bp-shellnav {
  flex-direction: row !important;
  padding: 0 !important;
  gap: 0;
  overflow: hidden;
}

/* Col 1 — macro-group icon rail */
.bp-rail {
  width: 60px;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  align-items: stretch;
  gap: 4px;
  padding: 16px 6px 12px;
  background: #0E1B2C;
}
.bp-rail-brand {
  display: flex;
  justify-content: center;
  margin-bottom: 10px;
}
.bp-rail-groups {
  display: flex;
  flex-direction: column;
  gap: 4px;
}
.bp-rail-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  padding: 9px 2px;
  border: 0;
  background: transparent;
  border-radius: 12px;
  color: rgba(231, 227, 216, 0.6);
  cursor: pointer;
  font-family: inherit;
  transition: background 0.18s, color 0.18s;
}
.bp-rail-icon { display: inline-flex; }
.bp-rail-label { font-size: 9.5px; font-weight: 600; letter-spacing: 0.01em; }
.bp-rail-item:hover { background: rgba(255, 255, 255, 0.06); color: #fff; }
.bp-rail-item:focus-visible { outline: 2px solid var(--color-accent); outline-offset: 2px; }
.bp-rail-item.is-active { background: rgba(31, 168, 160, 0.16); color: #fff; }
.bp-rail-item.is-active .bp-rail-icon { color: var(--color-accent); }
.bp-rail-item.locked { opacity: 0.3; cursor: not-allowed; }
.bp-rail-item.locked:hover { background: transparent; color: rgba(231, 227, 216, 0.6); }
.bp-rail-close { margin-top: auto; color: #E7E3D8; align-self: center; }

/* Col 2 — leaf panel for the selected group */
.bp-panel {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  background: #122236;
  border-left: 1px solid rgba(255, 255, 255, 0.06);
  padding: 16px 12px 12px;
}
.bp-panel-head { padding: 0 8px 14px; }
.bp-panel-head .bp-tenant { margin: 0; padding: 0; }
.bp-panel-title {
  font-size: 14px;
  font-weight: 700;
  color: var(--color-canvas-soft);
  margin-top: 6px;
  letter-spacing: -0.01em;
}
.bp-panel-nav {
  display: flex;
  flex-direction: column;
  gap: 1px;
  flex: 1;
  min-height: 0;
  overflow-y: auto;
  scrollbar-width: none;
  -ms-overflow-style: none;
}
.bp-panel-nav::-webkit-scrollbar { display: none; }
.bp-panel-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 8px;
  padding: 8px 10px;
  border-radius: 8px;
  color: rgba(231, 227, 216, 0.74);
  font-size: 13px;
  font-weight: 500;
  text-decoration: none;
  cursor: pointer;
  transition: background 0.15s, color 0.15s;
}
.bp-panel-item:hover { background: rgba(255, 255, 255, 0.05); color: #fff; }
.bp-panel-item:focus-visible { outline: 2px solid var(--color-accent); outline-offset: 2px; }
.bp-panel-item.is-active {
  background: rgba(31, 168, 160, 0.18);
  color: #fff;
  box-shadow: inset 2px 0 0 var(--color-accent);
}
.bp-panel-item .bp-badge {
  font-family: var(--font-mono, ui-monospace, "SF Mono", Menlo, monospace);
  font-size: 9px;
  padding: 1px 5px;
  border-radius: 4px;
  background: rgba(91, 108, 224, 0.22);
  color: #b7c2ff;
  font-weight: 600;
  flex-shrink: 0;
}

