tool_input.content:
/**
 * persona-switcher.test.tsx — Req4 proxy modal.
 * AC4.1 Modal role=dialog with eyebrow + title.
 * AC4.2 rows show name + {role}·{empId} + tier chips.
 * AC4.3 footer both locales.
 * AC4.4 selecting a non-active row → switchPersona + locale-prefixed landing.
 * AC4.5 active row disabled + "Active"/"ใช้อยู่".
 * AC4.7 exit → exitPersona + router.push /{locale}/home (NOT /admin).
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent, within } from '@testing-library/react';

const routerMock = vi.hoisted(() => ({ push: vi.fn() }));
const paramsMock = vi.hoisted(() => ({ locale: 'th' as string }));
const switchPersonaMock = vi.hoisted(() => vi.fn());
const exitPersonaMock = vi.hoisted(() => vi.fn());

type AuthShape = {
  email: string | null;
  originalUser: { username: string } | null;
  switchPersona: (u: unknown) => void;
  exitPersona: () => void;
};

const authMock = vi.hoisted(
  () =>
    ({
      email: 'employee@humi.test',
      originalUser: null,
      switchPersona: switchPersonaMock,
      exitPersona: exitPersonaMock,
    }) as AuthShape,
);

vi.mock('next/navigation', () => ({
  useRouter: vi.fn(() => routerMock),
  useParams: vi.fn(() => paramsMock),
}));

vi.mock('@/stores/auth-store', () => ({
  useAuthStore: vi.fn((selector: (s: AuthShape) => unknown) => selector(authMock)),
}));

// createPortal renders into document.body — keep it inline so queries see it.
vi.mock('react-dom', async (orig) => {
  const actual = await orig<typeof import('react-dom')>();
  return { ...actual, createPortal: (node: React.ReactNode) => node };
});

import { PersonaSwitcher } from '../PersonaSwitcher';
import { DEMO_USERS } from '@/lib/demo-users';

/** Open the modal by clicking the trigger pill. */
function openModal() {
  fireEvent.click(screen.getByRole('button', { name: /สลับบทบาท|Switch persona/ }));
}

beforeEach(() => {
  routerMock.push.mockClear();
  switchPersonaMock.mockClear();
  exitPersonaMock.mockClear();
  paramsMock.locale = 'th';
  authMock.email = 'employee@humi.test';
  authMock.originalUser = null;
});

describe('PersonaSwitcher — Req4 proxy modal', () => {
  it('AC4.1: opens a role=dialog Modal with the eyebrow + title', () => {
    render(<PersonaSwitcher />);
    openModal();
    const dialog = screen.getByRole('dialog');
    expect(within(dialog).getByText('RBAC · 4 ระดับ')).toBeInTheDocument();
    // The Modal renders the title in its header h2.
    expect(within(dialog).getAllByText('สลับบทบาท').length).toBeGreaterThan(0);
  });

  it('AC4.2: each row shows name + {role}·{empId}', () => {
    render(<PersonaSwitcher />);
    openModal();
    const ken = DEMO_USERS['ken@humi.test'];
    expect(screen.getByText(ken.name)).toBeInTheDocument();
    // role label · empId — Ken is HR Admin · KEN001
    expect(screen.getByText(`HR Admin · ${ken.id}`)).toBeInTheDocument();
  });

  it('AC4.2: a super-user row chips all four tiers A·B·C·D', () => {
    render(<PersonaSwitcher />);
    openModal();
    const adminRow = screen.getByText(DEMO_USERS['admin@humi.test'].name).closest('button')!;
    ['A', 'B', 'C', 'D'].forEach((t) =>
      expect(within(adminRow).getByText(t)).toBeInTheDocument(),
    );
  });

  it('AC4.3 (th): footer enforces RBAC copy', () => {
    render(<PersonaSwitcher />);
    openModal();
    expect(
      screen.getByText('บังคับใช้ RBAC — เห็นเฉพาะสิทธิ์ของแต่ละบทบาท'),
    ).toBeInTheDocument();
  });

  it('AC4.3 (en): footer enforces RBAC copy', () => {
    paramsMock.locale = 'en';
    render(<PersonaSwitcher />);
    openModal();
    expect(
      screen.getByText('RBAC enforced — you only see what each persona may access.'),
    ).toBeInTheDocument();
  });

  it('AC4.4: selecting a non-active row calls switchPersona + locale-prefixed landing', () => {
    render(<PersonaSwitcher />);
    openModal();
    // active = employee; pick admin (lands on /admin per landingForDemoUser).
    fireEvent.click(screen.getByText(DEMO_USERS['admin@humi.test'].name).closest('button')!);
    expect(switchPersonaMock).toHaveBeenCalledTimes(1);
    expect(routerMock.push).toHaveBeenCalledWith('/th/admin');
  });

  it('AC4.5: the active row is disabled and labeled "ใช้อยู่"', () => {
    render(<PersonaSwitcher />);
    openModal();
    const activeRow = screen
      .getByText(DEMO_USERS['employee@humi.test'].name)
      .closest('button')!;
    expect(activeRow).toBeDisabled();
    expect(within(activeRow).getByText('ใช้อยู่')).toBeInTheDocument();
  });

  it('AC4.5 (en): active row labeled "Active"', () => {
    paramsMock.locale = 'en';
    render(<PersonaSwitcher />);
    openModal();
    const activeRow = screen
      .getByText(DEMO_USERS['employee@humi.test'].name)
      .closest('button')!;
    expect(within(activeRow).getByText('Active')).toBeInTheDocument();
  });

  it('AC4.7: exit calls exitPersona + router.push /th/home, never /admin', () => {
    authMock.originalUser = { username: 'ผู้ดูแลระบบ HR' };
    render(<PersonaSwitcher />);
    openModal();
    fireEvent.click(screen.getByText(/กลับไปที่/));
    expect(exitPersonaMock).toHaveBeenCalledTimes(1);
    expect(routerMock.push).toHaveBeenCalledWith('/th/home');
    expect(routerMock.push).not.toHaveBeenCalledWith('/th/admin');
  });
});

/**
 * topbar-bells.test.tsx — Req6 inbox-then-bell topbar chrome.
 * AC6.1 both triggers present (TodoBell inbox + NotificationBell).
 * AC6.2 TodoBell renders the Mail (envelope) glyph; ListTodo absent.
 * AC6.3 badges derive from MOCK_TODOS / MOCK_IN_APP_NOTIFICATIONS, both bg-danger.
 * AC6.4 TodoBell precedes NotificationBell in DOM order.
 * AC6.5 footers → /{locale}/ess/workflows and /{locale}/admin/system/notifications.
 */

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { render, screen, fireEvent } from '@testing-library/react';

const navMock = vi.hoisted(() => ({ pathname: '/th/home' }));

vi.mock('next/navigation', () => ({
  usePathname: vi.fn(() => navMock.pathname),
  useRouter: vi.fn(() => ({ push: vi.fn(), replace: vi.fn() })),
  useParams: vi.fn(() => ({ locale: 'th' })),
}));

// Keep the persona switcher inert (no proxy) so the topbar renders its trigger
// without opening the modal — this suite is about the two bells.
vi.mock('@/stores/auth-store', () => ({
  useAuthStore: vi.fn(
    (selector: (s: Record<string, unknown>) => unknown) =>
      selector({
        email: 'ken@humi.test',
        userId: 'KEN001',
        username: 'จงรักษ์ ทานากะ',
        roles: ['hr_admin', 'employee'],
        originalUser: null,
        switchPersona: vi.fn(),
        exitPersona: vi.fn(),
        _hasHydrated: true,
      }),
  ),
}));

vi.mock('next/link', () => ({
  default: ({
    href,
    children,
    ...props
  }: React.AnchorHTMLAttributes<HTMLAnchorElement> & { href: string }) => (
    <a href={href} {...props}>
      {children}
    </a>
  ),
}));

import { Topbar } from '../Topbar';
import { MOCK_TODOS } from '@/data/todos/mock';
import { MOCK_IN_APP_NOTIFICATIONS } from '@/data/notifications/mock';

const unreadTodos = MOCK_TODOS.filter((t) => !t.done).length;
const unreadNotifs = MOCK_IN_APP_NOTIFICATIONS.filter((n) => !n.read).length;

function inboxTrigger() {
  return screen.getByRole('button', { name: 'กล่องข้อความเข้า' });
}
function bellTrigger() {
  return screen.getByRole('button', { name: 'การแจ้งเตือน' });
}

beforeEach(() => {
  navMock.pathname = '/th/home';
});

describe('Topbar bells — Req6', () => {
  it('AC6.1: both the inbox and the notification triggers render', () => {
    render(<Topbar title="หน้าหลัก" />);
    expect(inboxTrigger()).toBeInTheDocument();
    expect(bellTrigger()).toBeInTheDocument();
  });

  it('AC6.2: TodoBell trigger uses the Mail glyph (lucide-mail), not ListTodo', () => {
    const { container } = render(<Topbar title="หน้าหลัก" />);
    const inbox = inboxTrigger();
    expect(inbox.querySelector('svg.lucide-mail')).not.toBeNull();
    // No list-todo icon anywhere in the topbar.
    expect(container.querySelector('svg.lucide-list-todo')).toBeNull();
  });

  it('AC6.3: the inbox badge reflects the unread MOCK_TODOS count, in bg-danger', () => {
    render(<Topbar title="หน้าหลัก" />);
    const badge = inboxTrigger().querySelector('span[aria-label]')!;
    expect(badge).toHaveClass('bg-danger');
    expect(badge.textContent).toBe(unreadTodos > 9 ? '9+' : String(unreadTodos));
  });

  it('AC6.3: the notification badge reflects MOCK_IN_APP_NOTIFICATIONS, in bg-danger', () => {
    render(<Topbar title="หน้าหลัก" />);
    const badge = bellTrigger().querySelector('span[aria-label]')!;
    expect(badge).toHaveClass('bg-danger');
    expect(badge.textContent).toBe(unreadNotifs > 9 ? '9+' : String(unreadNotifs));
  });

  it('AC6.4: TodoBell precedes NotificationBell in DOM order', () => {
    render(<Topbar title="หน้าหลัก" />);
    const inbox = inboxTrigger();
    const bell = bellTrigger();
    // Node.compareDocumentPosition: FOLLOWING (4) means bell comes after inbox.
    expect(inbox.compareDocumentPosition(bell) & Node.DOCUMENT_POSITION_FOLLOWING).toBeTruthy();
  });

  it('AC6.5: TodoBell footer links to /{locale}/ess/workflows', () => {
    render(<Topbar title="หน้าหลัก" />);
    fireEvent.click(inboxTrigger());
    const footer = screen.getByText('ดูงานทั้งหมด').closest('a')!;
    expect(footer).toHaveAttribute('href', '/th/ess/workflows');
  });

  it('AC6.5: NotificationBell footer links to /{locale}/admin/system/notifications', () => {
    render(<Topbar title="หน้าหลัก" />);
    fireEvent.click(bellTrigger());
    const footer = screen.getByText('ดูการแจ้งเตือนทั้งหมด').closest('a')!;
    expect(footer).toHaveAttribute('href', '/th/admin/system/notifications');
  });
});

