tool_input.content:
// Roster & Shifts — mock seed (MOCKUP ONLY, no persistence / API).
// Mirrors the canonical reference (roster-ref-2026-05-25.png): 6 staff, a 24h
// hourly schedule with per-shift break windows, per-employee total hours, and a
// coverage summary. Shift positions are expressed in hours (0–24) so the Gantt
// can absolute-position each cell (left = start/24, width = duration/24).

/** Four shift archetypes — each maps to a tokenized class set in RosterGantt. */
export type ShiftType = 'manager' | 'partTime' | 'night' | 'regular';

/** Coverage status per hour — maps to a tokenized cov-cell class. */
export type CoverageStatus = 'ok' | 'gap' | 'over' | 'off';

/** Employment type chip shown in the employee meta line (mono, uppercase). */
export type EmploymentType = 'FT' | 'PT' | 'MOD';

export interface RosterShift {
  id: string;
  type: ShiftType;
  /** 0–24 — start hour of the shift. */
  start: number;
  /** 0–24 — end hour of the shift (always > start for these mocks). */
  end: number;
  /** Break window inside the shift [start,end] in hours, or null if none. */
  breakStart: number | null;
  breakEnd: number | null;
  labelTh: string;
  labelEn: string;
}

export interface RosterRow {
  id: string;
  /** Display name. */
  name: string;
  /** Avatar initials (2 chars). */
  initials: string;
  employmentType: EmploymentType;
  roleTh: string;
  roleEn: string;
  /** FOH / BOH / FLOOR — work area, shown in meta line. */
  location: string;
  /** Target hours for the period; under-target totals render in pumpkin. */
  targetHours: number;
  shifts: RosterShift[];
}

export const ROSTER_HOURS = 24;

/** "Now" marker — static demo time matching the reference (14:24). */
export const NOW_HOUR = 14;
export const NOW_MINUTE = 24;

/** Bilingual labels for each shift archetype (consumed by the legend). */
export const SHIFT_TYPE_LABELS: Record<ShiftType, { th: string; en: string }> = {
  manager: { th: 'กะหัวหน้า', en: 'Manager' },
  partTime: { th: 'พาร์ทไทม์', en: 'Part-time' },
  night: { th: 'กะกลางคืน', en: 'Night' },
  regular: { th: 'กะปกติ', en: 'Regular' },
};

function shift(
  id: string,
  type: ShiftType,
  start: number,
  end: number,
  breakStart: number | null = null,
  breakEnd: number | null = null,
): RosterShift {
  return {
    id,
    type,
    start,
    end,
    breakStart,
    breakEnd,
    labelTh: SHIFT_TYPE_LABELS[type].th,
    labelEn: SHIFT_TYPE_LABELS[type].en,
  };
}

// ── The reference's exact 6 staff ──────────────────────────────────────────
//   Somchai K.  FT  SHIFT LEAD         FOH   07:00–16:00  9.0h
//   Somsri P.   FT  CASHIER            FOH   09:00–18:00  9.0h
//   Panji Dwi   PT  FLOOR              —     13:00–17:00  4.0h
//   Anan S.     MOD MANAGER ON DUTY    —     10:00–19:00  9.0h
//   Mali T.     FT  BARISTA            FOH   06:00–14:00  8.0h
//   Krit J.     FT  STOCK              BOH   16:00–23:00  7.0h
export const ROSTER_ROWS: RosterRow[] = [
  {
    id: 'row-1',
    name: 'Somchai K.',
    initials: 'SK',
    employmentType: 'FT',
    roleTh: 'หัวหน้ากะ',
    roleEn: 'Shift Lead',
    location: 'FOH',
    targetHours: 9,
    shifts: [shift('s-1a', 'manager', 7, 16, 12, 13)],
  },
  {
    id: 'row-2',
    name: 'Somsri P.',
    initials: 'SP',
    employmentType: 'FT',
    roleTh: 'แคชเชียร์',
    roleEn: 'Cashier',
    location: 'FOH',
    targetHours: 9,
    shifts: [shift('s-2a', 'regular', 9, 18, 13, 14)],
  },
  {
    id: 'row-3',
    name: 'Panji Dwi',
    initials: 'PD',
    employmentType: 'PT',
    roleTh: 'พนักงานหน้าร้าน',
    roleEn: 'Floor',
    location: 'FLOOR',
    targetHours: 4,
    shifts: [shift('s-3a', 'partTime', 13, 17)],
  },
  {
    id: 'row-4',
    name: 'Anan S.',
    initials: 'AS',
    employmentType: 'MOD',
    roleTh: 'ผู้จัดการเวร',
    roleEn: 'Manager on Duty',
    location: 'FOH',
    targetHours: 9,
    shifts: [shift('s-4a', 'manager', 10, 19, 14, 15)],
  },
  {
    id: 'row-5',
    name: 'Mali T.',
    initials: 'MT',
    employmentType: 'FT',
    roleTh: 'บาริสต้า',
    roleEn: 'Barista',
    location: 'FOH',
    targetHours: 9, // under target (8.0h) -> renders pumpkin
    shifts: [shift('s-5a', 'regular', 6, 14, 10, 11)],
  },
  {
    id: 'row-6',
    name: 'Krit J.',
    initials: 'KJ',
    employmentType: 'FT',
    roleTh: 'คลังสินค้า',
    roleEn: 'Stock',
    location: 'BOH',
    targetHours: 9, // under target (7.0h) -> renders pumpkin
    shifts: [shift('s-6a', 'night', 16, 23, 19, 20)],
  },
];

/** Net paid hours for a shift = duration minus its break window. */
export function shiftHours(s: RosterShift): number {
  const dur = s.end - s.start;
  const brk = s.breakStart != null && s.breakEnd != null ? s.breakEnd - s.breakStart : 0;
  return dur - brk;
}

/** Total paid hours across a row's shifts. */
export function rowTotalHours(row: RosterRow): number {
  return row.shifts.reduce((n, s) => n + shiftHours(s), 0);
}

// 24-hour coverage row tuned to the reference summary: 12 gaps, peak 13–16,
// deficit −16 hrs. ok = adequately staffed, over = peak overlap, gap =
// understaffed against demand, off = no demand / closed.
export const COVERAGE: CoverageStatus[] = [
  'off', 'off', 'off', 'off', 'off', 'off', // 00–05 closed
  'gap', 'gap', 'gap', 'ok', 'ok', 'ok',    // 06–11 ramp, early gaps
  'gap', 'over', 'over', 'over', 'over', 'ok', // 12–17 afternoon peak 13–16
  'gap', 'gap', 'gap', 'gap', 'gap', 'gap', // 18–23 evening understaffed
];

/** Coverage summary shown in the strip label + total slot. */
export const COVERAGE_SUMMARY = {
  gaps: 12,
  peakStart: 13,
  peakEnd: 16,
  deficitHrs: -16,
};

/** Avatar background tokens (teal/indigo/pumpkin family — NO hex, NO red). */
export const AVATAR_BG: Record<string, string> = {
  'row-1': 'bg-accent',
  'row-2': 'bg-[var(--color-accent-alt)]',
  'row-3': 'bg-danger',
  'row-4': 'bg-[var(--color-accent-alt)]',
  'row-5': 'bg-accent',
  'row-6': 'bg-ink-soft',
};

// RosterGantt — employee rows × 24 hour columns, with a TOTAL column.
// Faithful to roster-ref-2026-05-25.png:
//   grid = [240px employee][76px total][repeat(24,1fr) hours]
//   shift cell shows the TIME RANGE (left, mono) + DURATION (right, dimmed);
//   shift TYPE is conveyed by COLOR only (no type-name text).
//   break window = diagonal-hatch overlay; NOW = thin pumpkin vertical line.
// Tokens only: NO hardcoded hex, NO Tailwind red/rose/pink (danger = pumpkin),
// text sizes via the Tailwind scale (Humi R4 contract — no arbitrary px text).

'use client';

import { useLocale } from 'next-intl';
import { cn } from '@/lib/utils';
import {
  ROSTER_HOURS,
  NOW_HOUR,
  NOW_MINUTE,
  AVATAR_BG,
  rowTotalHours,
  shiftHours,
  type RosterRow,
  type RosterShift,
  type ShiftType,
} from '@/data/roster/mock';

// Shift archetype -> tokenized class set (AC1.2 / AC1.8 mapping):
//   manager  indigo -> accent-alt-soft bg + accent-alt border
//   partTime amber  -> warning-soft bg + warning border  (NEVER bg-warning-tint)
//   night    navy   -> ink bg + LIGHT canvas-soft text (NOT text-ink)
//   regular  teal   -> accent-soft bg + accent text + accent border
export const SHIFT_TYPE_CLASS: Record<ShiftType, string> = {
  manager:
    'bg-[var(--color-accent-alt-soft)] border-[var(--color-accent-alt)] text-ink',
  partTime: 'bg-warning-soft border-warning text-ink',
  night: 'bg-[var(--color-ink)] text-[var(--color-canvas-soft)] border-[var(--color-ink)]',
  regular: 'bg-accent-soft text-accent border-accent',
};

const GRID_COLS = `240px 76px repeat(${ROSTER_HOURS}, minmax(0,1fr))`;

function pct(hour: number): number {
  return (hour / ROSTER_HOURS) * 100;
}

function fmtHour(h: number): string {
  return `${Math.floor(h).toString().padStart(2, '0')}:00`;
}

function fmtHours(n: number): string {
  return `${n.toFixed(1)}h`;
}

export interface RosterGanttProps {
  rows: RosterRow[];
  onShiftClick?: (shift: RosterShift, row: RosterRow) => void;
}

export function RosterGantt({ rows, onShiftClick }: RosterGanttProps) {
  const locale = useLocale();
  const isTh = locale !== 'en';
  // Hour axis labels 01..24 (ref style), one per column.
  const hourLabels = Array.from({ length: ROSTER_HOURS }, (_, i) => i + 1);
  const nowLeft = ((NOW_HOUR + NOW_MINUTE / 60) / ROSTER_HOURS) * 100;

  return (
    <div data-testid="roster-gantt" className="overflow-x-auto">
      <div className="min-w-[980px]">
        {/* Hour header */}
        <div
          className="grid items-center border-b border-hairline"
          style={{ gridTemplateColumns: GRID_COLS }}
          role="row"
        >
          <div className="px-4 py-2.5 font-mono text-[length:var(--text-eyebrow)] font-semibold uppercase tracking-[0.1em] text-ink-faint">
            {isTh ? 'พนักงาน' : 'Employee'}
          </div>
          <div className="px-2 py-2.5 font-mono text-[length:var(--text-eyebrow)] font-semibold uppercase tracking-[0.1em] text-ink-faint">
            {isTh ? 'รวม' : 'Total'}
          </div>
          {hourLabels.map((h) => (
            <div
              key={h}
              data-testid="hour-col"
              className="border-l border-hairline-soft py-2.5 text-center font-mono text-[length:var(--text-eyebrow)] font-semibold text-ink-faint"
            >
              {h.toString().padStart(2, '0')}
            </div>
          ))}
        </div>

        {/* Rows + a single NOW line overlay spanning all rows */}
        <div className="relative">
          {/* NOW line — thin pumpkin vertical marker with a dot at the top */}
          <div
            data-testid="now-line"
            aria-hidden
            className="pointer-events-none absolute top-0 bottom-0 z-20 w-px bg-danger"
            style={{
              // offset into the hours track: 240 + 76 = 316px label columns,
              // then nowLeft% of the remaining width.
              left: `calc(316px + (100% - 316px) * ${nowLeft / 100})`,
            }}
          >
            <span className="absolute -left-[3px] -top-[3px] h-2 w-2 rounded-full bg-danger" />
          </div>

          {rows.map((row) => {
            const total = rowTotalHours(row);
            const under = total < row.targetHours;
            return (
              <div
                key={row.id}
                data-testid="roster-row"
                className="grid items-stretch border-b border-hairline-soft"
                style={{ gridTemplateColumns: GRID_COLS }}
                role="row"
              >
                {/* Employee cell — avatar + name + mono meta line */}
                <div className="flex items-center gap-3 px-4 py-3.5">
                  <span
                    className={cn(
                      'inline-flex h-[30px] w-[30px] shrink-0 items-center justify-center rounded-full text-xs font-bold text-white',
                      AVATAR_BG[row.id] ?? 'bg-accent',
                    )}
                    aria-hidden
                  >
                    {row.initials}
                  </span>
                  <span className="flex min-w-0 flex-col">
                    <span className="truncate font-display text-base font-semibold leading-tight tracking-tight text-ink">
                      {row.name}
                    </span>
                    <span className="mt-0.5 truncate font-mono text-xs uppercase tracking-[0.02em] text-ink-muted">
                      {row.employmentType} · {isTh ? row.roleTh : row.roleEn} ·{' '}
                      {row.location}
                    </span>
                  </span>
                </div>

                {/* TOTAL cell — pumpkin when under target */}
                <div className="flex items-center px-2 py-3.5">
                  <span
                    data-testid="total-cell"
                    data-under={under ? 'true' : 'false'}
                    className={cn(
                      'font-mono text-sm font-bold tracking-[0.02em]',
                      under ? 'text-danger' : 'text-ink',
                    )}
                  >
                    {fmtHours(total)}
                  </span>
                </div>

                {/* Shift track — spans all 24 hour columns */}
                <div
                  data-testid="shift-track"
                  className="relative min-h-[58px]"
                  style={{ gridColumn: `3 / span ${ROSTER_HOURS}` }}
                >
                  {/* faint hour gridlines */}
                  <div
                    aria-hidden
                    className="pointer-events-none absolute inset-0 grid"
                    style={{ gridTemplateColumns: `repeat(${ROSTER_HOURS}, minmax(0,1fr))` }}
                  >
                    {Array.from({ length: ROSTER_HOURS }, (_, i) => (
                      <span key={i} className="border-l border-hairline-soft first:border-l-0" />
                    ))}
                  </div>

                  {row.shifts.map((s) => {
                    const left = pct(s.start);
                    const width = pct(s.end - s.start);
                    const dur = shiftHours(s);
                    const hasBreak = s.breakStart != null && s.breakEnd != null;
                    // break position relative to the shift cell width
                    const span = s.end - s.start;
                    const brkLeft = hasBreak ? ((s.breakStart! - s.start) / span) * 100 : 0;
                    const brkWidth = hasBreak
                      ? ((s.breakEnd! - s.breakStart!) / span) * 100
                      : 0;
                    return (
                      <button
                        key={s.id}
                        type="button"
                        data-testid="shift-cell"
                        data-shift-type={s.type}
                        onClick={() => onShiftClick?.(s, row)}
                        title={`${fmtHour(s.start)} – ${fmtHour(s.end)} · ${fmtHours(dur)}`}
                        aria-label={`${row.name} ${fmtHour(s.start)}–${fmtHour(s.end)} ${fmtHours(dur)}`}
                        className={cn(
                          'absolute top-[11px] bottom-[11px] z-10 overflow-hidden rounded-[7px] border px-2.5',
                          'flex items-center justify-between font-mono text-xs font-semibold tracking-[0.02em]',
                          'shadow-[0_1px_0_rgba(14,27,44,0.04)] transition-[filter] hover:brightness-[0.97]',
                          'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent focus-visible:ring-offset-1',
                          SHIFT_TYPE_CLASS[s.type],
                        )}
                        style={{ left: `${left}%`, width: `calc(${width}% - 4px)` }}
                      >
                        {/* break stripe — tokenized diagonal hatch (no hex) */}
                        {hasBreak && (
                          <span
                            data-testid="break-stripe"
                            aria-hidden
                            className="pointer-events-none absolute top-[3px] bottom-[3px] rounded-[4px] [background:repeating-linear-gradient(45deg,color-mix(in_oklab,currentColor_55%,transparent)_0_3px,transparent_3px_6px)]"
                            style={{ left: `${brkLeft}%`, width: `${brkWidth}%` }}
                          />
                        )}
                        <span className="relative z-10 truncate">
                          {fmtHour(s.start)} – {fmtHour(s.end)}
                        </span>
                        <span className="relative z-10 ml-2 shrink-0 font-medium opacity-65">
                          {fmtHours(dur)}
                        </span>
                      </button>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// CoverageStrip — coverage row sibling to RosterGantt. Matches the reference:
//   [240px label][76px deficit][24 coverage cells] grid.
//   label = "COVERAGE" eyebrow + summary "12 gaps · Peak 13–16".
//   deficit slot = "−16 hrs" in pumpkin (text-danger, no bg).
//   cells: ok=bg-accent, gap=bg-danger (pumpkin), over=accent-alt opacity-60,
//   off=bg-hairline thin (4px). Tokens only — NO hex, NO Tailwind red.

'use client';

import { useLocale } from 'next-intl';
import { cn } from '@/lib/utils';
import {
  COVERAGE,
  COVERAGE_SUMMARY,
  ROSTER_HOURS,
  type CoverageStatus,
} from '@/data/roster/mock';

// status -> token class (ref .cov-cell map; gap = pumpkin = --color-danger).
const COV_CELL_CLASS: Record<CoverageStatus, string> = {
  ok: 'bg-accent',
  gap: 'bg-danger',
  over: 'bg-[var(--color-accent-alt)] opacity-60',
  off: 'bg-hairline',
};

const COV_LABEL: Record<CoverageStatus, { th: string; en: string }> = {
  ok: { th: 'พอเพียง', en: 'Covered' },
  gap: { th: 'ขาดคน', en: 'Gap' },
  over: { th: 'เกินจำเป็น', en: 'Over' },
  off: { th: 'ปิดกะ', en: 'Off' },
};

const GRID_COLS = `240px 76px repeat(${ROSTER_HOURS}, minmax(0,1fr))`;

export function CoverageStrip({ coverage = COVERAGE }: { coverage?: CoverageStatus[] }) {
  const locale = useLocale();
  const isTh = locale !== 'en';
  const { gaps, peakStart, peakEnd, deficitHrs } = COVERAGE_SUMMARY;

  const summary = isTh
    ? `${gaps} ช่องว่าง · พีค ${peakStart}–${peakEnd}`
    : `${gaps} gaps · Peak ${peakStart}–${peakEnd}`;

  return (
    <div
      data-testid="coverage-strip"
      className="grid items-stretch bg-canvas-soft"
      style={{ gridTemplateColumns: GRID_COLS }}
      role="row"
      aria-label={isTh ? 'ความครอบคลุมกะรายชั่วโมง' : 'Hourly shift coverage'}
    >
      {/* Label column */}
      <div className="flex flex-col justify-center gap-1 px-4 py-3.5">
        <span className="font-mono text-[length:var(--text-eyebrow)] font-bold uppercase tracking-[0.14em] text-ink-faint">
          {isTh ? 'ความครอบคลุม' : 'Coverage'}
        </span>
        <span
          data-testid="coverage-summary"
          className="font-display text-sm tracking-tight text-ink-soft"
        >
          {summary}
        </span>
      </div>

      {/* Deficit slot (aligns with the gantt TOTAL column) */}
      <div className="flex items-center gap-1 px-2 py-3.5">
        <span data-testid="coverage-deficit" className="font-mono font-bold text-danger">
          {deficitHrs} {isTh ? 'ชม.' : 'hrs'}
        </span>
      </div>

      {/* 24 coverage cells */}
      <div
        className="grid items-center gap-0.5 border-l border-hairline-soft py-3.5"
        style={{
          gridColumn: `3 / span ${ROSTER_HOURS}`,
          gridTemplateColumns: `repeat(${ROSTER_HOURS}, minmax(0,1fr))`,
        }}
      >
        {coverage.slice(0, ROSTER_HOURS).map((status, hour) => {
          const lbl = COV_LABEL[status];
          return (
            <div
              key={hour}
              data-testid="cov-cell"
              data-status={status}
              title={`${hour.toString().padStart(2, '0')}:00 · ${isTh ? lbl.th : lbl.en}`}
              aria-label={`${hour.toString().padStart(2, '0')}:00 ${isTh ? lbl.th : lbl.en}`}
              className={cn(
                'rounded',
                // off is a thin hairline rule; the rest fill the row height
                status === 'off' ? 'h-1' : 'h-[18px]',
                COV_CELL_CLASS[status],
              )}
            />
          );
        })}
      </div>
    </div>
  );
}

// Roster & Shifts — 24h Gantt board matching roster-ref-2026-05-25.png.
// Header breadcrumb + two-tone title, dept/week toolbar, Export + Bulk assign,
// card with "Hourly schedule" + STAFF/HRS/NOW meta, coverage strip, footer.
// Swap stays reachable via row action + ?panel=swap (no top swap button).
// MOCKUP ONLY: all actions resolve to a transient inline toast (no API).

'use client';

import { useMemo, useState } from 'react';
import { useLocale } from 'next-intl';
import { useSearchParams } from 'next/navigation';
import { CalendarRange, ChevronDown, Download, Plus } from 'lucide-react';
import { Card, Button, EmptyState } from '@/components/humi';
import { cn } from '@/lib/utils';
import { RosterGantt } from '@/components/roster/RosterGantt';
import { CoverageStrip } from '@/components/roster/CoverageStrip';
import { ShiftEditorDrawer } from '@/components/roster/ShiftEditorDrawer';
import { ShiftSwapModal } from '@/components/roster/ShiftSwapModal';
import { BulkAssignModal } from '@/components/roster/BulkAssignModal';
import {
  ROSTER_ROWS,
  SHIFT_TYPE_LABELS,
  NOW_HOUR,
  NOW_MINUTE,
  rowTotalHours,
  type RosterRow,
  type RosterShift,
} from '@/data/roster/mock';

// Legend swatches reuse the same archetype tokens as the Gantt cells.
const LEGEND_CLASS: Record<string, string> = {
  manager: 'bg-[var(--color-accent-alt-soft)] border-[var(--color-accent-alt)]',
  partTime: 'bg-warning-soft border-warning',
  night: 'bg-[var(--color-ink)] border-[var(--color-ink)]',
  regular: 'bg-accent-soft border-accent',
};

export default function RosterPage() {
  const locale = useLocale();
  const isTh = locale !== 'en';
  const searchParams = useSearchParams();

  const rows = ROSTER_ROWS;

  // ── Drawer + modal local state (mockup only) ──────────────────────────────
  const [editor, setEditor] = useState<{
    shift: RosterShift | null;
    employee: string;
  } | null>(null);
  const [swapOpen, setSwapOpen] = useState(
    () => searchParams?.get('panel') === 'swap',
  );
  const [bulkOpen, setBulkOpen] = useState(false);
  const [toast, setToast] = useState<string | null>(null);

  // Keep swap modal in sync with ?panel=swap (deep-link).
  const panelSwap = searchParams?.get('panel') === 'swap';
  const swapVisible = swapOpen || panelSwap;

  const flash = (msg: string) => {
    setToast(msg);
    window.setTimeout(() => setToast(null), 4000);
  };

  const handleShiftClick = (shift: RosterShift, row: RosterRow) => {
    setEditor({ shift, employee: row.name });
  };

  const handleEditorSave = () => {
    setEditor(null);
    flash(isTh ? 'บันทึกกะแล้ว (ตัวอย่าง)' : 'Shift saved (demo)');
  };

  const handleSwapSubmit = () => {
    setSwapOpen(false);
    flash(isTh ? 'ส่งคำขอสลับกะแล้ว (ตัวอย่าง)' : 'Swap requested (demo)');
  };

  const handleBulkApply = (ids: string[]) => {
    setBulkOpen(false);
    flash(
      isTh
        ? `กำหนดกะให้ ${ids.length} คนแล้ว (ตัวอย่าง)`
        : `Assigned ${ids.length} employees (demo)`,
    );
  };

  const hasRows = rows.length > 0;
  const legendEntries = useMemo(
    () => Object.keys(SHIFT_TYPE_LABELS) as Array<keyof typeof SHIFT_TYPE_LABELS>,
    [],
  );

  // Card-header meta: staff count + summed paid hours + static NOW.
  const staffCount = rows.length;
  const totalHrs = useMemo(
    () => rows.reduce((n, r) => n + rowTotalHours(r), 0),
    [rows],
  );
  const nowLabel = `${NOW_HOUR.toString().padStart(2, '0')}:${NOW_MINUTE.toString().padStart(2, '0')}`;
  const headerMeta = isTh
    ? `${staffCount} คน · ${totalHrs.toFixed(1)} ชม. · ตอนนี้ ${nowLabel}`
    : `${staffCount} STAFF · ${totalHrs.toFixed(1)} HRS · NOW ${nowLabel}`;

  return (
    <div className="pb-8 flex flex-col gap-6">
      {/* Header — breadcrumb eyebrow + two-tone title + subtitle */}
      <header className="flex flex-col gap-1">
        <span className="font-mono text-[length:var(--text-eyebrow)] font-semibold uppercase tracking-[0.14em] text-ink-faint">
          {isTh
            ? 'HUMI • บริหารทีม • ตารางกะ'
            : 'HUMI • TEAM MANAGEMENT • ROSTER & SHIFTS'}
        </span>
        <h1 className="font-display text-[length:var(--text-display-h1)] font-semibold leading-[var(--text-display-h1--line-height)] tracking-tight text-ink">
          {isTh ? (
            <>
              ตาราง<span className="italic font-medium text-accent">กะ</span>
            </>
          ) : (
            <>
              Roster <span className="italic font-medium text-accent">&amp; Shifts</span>
            </>
          )}
        </h1>
        <p className="text-small text-ink-muted mt-1">
          {isTh ? 'คลิกที่กะเพื่อแก้ไขเวลา' : 'Click a shift to override times.'}
        </p>
      </header>

      {/* Toolbar: LEFT filters · RIGHT actions */}
      <div className="flex flex-wrap items-center gap-3">
        <label className="inline-flex items-center gap-2 rounded-[var(--radius-md)] border border-hairline bg-surface px-3 py-2 text-small text-ink-soft">
          <select
            aria-label={isTh ? 'แผนก' : 'Department'}
            className="bg-transparent pr-1 text-small text-ink-soft focus-visible:outline-none"
            defaultValue="all"
          >
            <option value="all">{isTh ? 'ทุกแผนก' : 'All departments'}</option>
            <option value="foh">FOH</option>
            <option value="boh">BOH</option>
            <option value="floor">{isTh ? 'หน้าร้าน' : 'Floor'}</option>
          </select>
        </label>
        <label className="inline-flex items-center gap-2 rounded-[var(--radius-md)] border border-hairline bg-surface px-3 py-2 text-small text-ink-soft">
          <CalendarRange size={15} className="text-ink-muted" aria-hidden />
          <select
            aria-label={isTh ? 'สัปดาห์' : 'Week'}
            className="bg-transparent pr-1 text-small text-ink-soft focus-visible:outline-none"
            defaultValue="w1"
          >
            <option value="w1">{isTh ? 'สัปดาห์ 19–25 พ.ค.' : 'Week of 19–25 May'}</option>
            <option value="w2">{isTh ? 'สัปดาห์ 26 พ.ค.–1 มิ.ย.' : 'Week of 26 May–1 Jun'}</option>
          </select>
        </label>
        <div className="ml-auto flex flex-wrap gap-3">
          <Button
            variant="secondary"
            leadingIcon={<Download size={16} />}
            onClick={() => flash(isTh ? 'กำลังส่งออก (ตัวอย่าง)' : 'Exporting (demo)')}
          >
            {isTh ? 'ส่งออก' : 'Export'}
          </Button>
          <Button
            variant="primary"
            leadingIcon={<Plus size={16} />}
            onClick={() => setBulkOpen(true)}
          >
            {isTh ? 'กำหนดกะแบบกลุ่ม' : 'Bulk assign'}
          </Button>
        </div>
      </div>

      {/* Transient mockup toast */}
      {toast && (
        <div
          role="status"
          className="rounded-[var(--radius-md)] border border-accent bg-accent-soft px-4 py-2.5 text-small font-medium text-accent"
        >
          {toast}
        </div>
      )}

      {/* Board */}
      {hasRows ? (
        <Card variant="raised" size="lg" flush>
          {/* Card header: title + meta line */}
          <div className="flex flex-wrap items-center justify-between gap-3 border-b border-hairline px-5 py-4">
            <h2 className="font-display text-[length:var(--text-display-h3)] font-semibold tracking-tight text-ink">
              {isTh ? 'ตารางรายชั่วโมง' : 'Hourly schedule'}
            </h2>
            <span className="font-mono text-small uppercase tracking-[0.04em] text-ink-muted">
              {headerMeta}
            </span>
          </div>

          <RosterGantt rows={rows} onShiftClick={handleShiftClick} />
          <CoverageStrip />

          {/* Legend */}
          <div className="flex flex-wrap items-center gap-4 border-t border-hairline-soft px-5 py-3">
            {legendEntries.map((t) => (
              <span key={t} className="inline-flex items-center gap-2 font-mono text-xs text-ink-muted">
                <span
                  className={cn('inline-block h-2.5 w-4 rounded-sm border', LEGEND_CLASS[t])}
                  aria-hidden
                />
                {isTh ? SHIFT_TYPE_LABELS[t].th : SHIFT_TYPE_LABELS[t].en}
              </span>
            ))}
          </div>

          {/* Footer hint */}
          <div className="border-t border-hairline-soft px-5 py-3">
            <span className="text-small text-ink-muted">
              {isTh ? 'คลิกที่กะเพื่อแก้ไข' : 'Click a shift to override'}
            </span>
          </div>
        </Card>
      ) : (
        <EmptyState
          icon={CalendarRange}
          titleTh="ยังไม่มีตารางกะ"
          titleEn="No roster yet"
          descTh="เพิ่มกะให้พนักงานเพื่อเริ่มจัดตารางกะรายวัน"
          descEn="Assign shifts to employees to start building the daily roster."
        />
      )}

      {/* Shift editor drawer */}
      <ShiftEditorDrawer
        open={editor !== null}
        shift={editor?.shift ?? null}
        employeeName={editor?.employee}
        onClose={() => setEditor(null)}
        onSave={handleEditorSave}
      />

      {/* Swap modal — reachable via ?panel=swap or row action */}
      <ShiftSwapModal
        open={swapVisible}
        onClose={() => setSwapOpen(false)}
        onSubmit={handleSwapSubmit}
      />

      {/* Bulk assign modal */}
      <BulkAssignModal
        open={bulkOpen}
        onClose={() => setBulkOpen(false)}
        onApply={handleBulkApply}
      />
    </div>
  );
}

