// Roster & Shifts — TimeFirst mock seed (MOCKUP ONLY, no persistence / API).
// Ported from the "Roster_TimeFirst" design variant: a weekly grid where each
// cell carries a shift type + actual in/out times. The shift type supplies a
// DEFAULT time window; when a cell's times differ from that default it is an
// "override" (rendered with a blue dot). See app/[locale]/roster/page.tsx.

/** Shift type keys. M/A/N carry default time windows; O/L are time-less. */
export type ShiftCode = 'M' | 'A' | 'N' | 'O' | 'L';

/**
 * Shift-type definition. The domain shift palette (bg/fg) is intentional and
 * centralized here — the hex values live as `--shift-*` tokens in globals.css
 * and are referenced via var(); never scatter raw hex in the component.
 * `start`/`end` are the default window ('' for O/L).
 */
export interface ShiftDef {
  /** Cell background (var(--shift-*-bg) — intentional domain palette). */
  bg: string;
  /** Cell foreground/text (var(--shift-*-fg) — intentional domain palette). */
  fg: string;
  labelTh: string;
  labelEn: string;
  /** Default start time 'HH:MM' (empty for O/L). */
  start: string;
  /** Default end time 'HH:MM' (empty for O/L). */
  end: string;
}

/** Per-day cell: a shift code plus the actual in/out times (omitted for O/L). */
export interface RosterCell {
  t: ShiftCode;
  /** Actual start 'HH:MM' (absent for O/L). */
  s?: string;
  /** Actual end 'HH:MM' (absent for O/L). */
  e?: string;
}

/** Avatar tone — maps to a `.humi-avatar--{tone}` modifier in globals.css. */
export type AvatarTone = 'sage' | 'teal' | 'coral' | 'butter';

export interface RosterStaff {
  id: string;
  /** Display name. */
  name: string;
  roleTh: string;
  roleEn: string;
  /** Avatar initials. */
  initials: string;
  /** Avatar tone modifier. */
  tone: AvatarTone;
  /** Total scheduled hours for the week (shown in the hours column). */
  hours: number;
  /** Seven cells — Mon..Sun. */
  days: RosterCell[];
}

/**
 * Shift defaults — the type carries the default time window. The bg/fg colors
 * are the intentional domain palette, centralized as `--shift-*` tokens in
 * globals.css and referenced here via var() (never inline hex in the page).
 */
export const SHIFT_DEFS: Record<ShiftCode, ShiftDef> = {
  M: { bg: 'var(--shift-m-bg)', fg: 'var(--shift-m-fg)', labelTh: 'เช้า', labelEn: 'Morning', start: '08:00', end: '17:00' },
  A: { bg: 'var(--shift-a-bg)', fg: 'var(--shift-a-fg)', labelTh: 'บ่าย', labelEn: 'Afternoon', start: '14:00', end: '23:00' },
  N: { bg: 'var(--shift-n-bg)', fg: 'var(--shift-n-fg)', labelTh: 'ดึก', labelEn: 'Night', start: '22:00', end: '07:00' },
  O: { bg: 'var(--shift-o-bg)', fg: 'var(--shift-o-fg)', labelTh: 'หยุด', labelEn: 'Off', start: '', end: '' },
  L: { bg: 'var(--shift-l-bg)', fg: 'var(--shift-l-fg)', labelTh: 'ลา', labelEn: 'Leave', start: '', end: '' },
};

/**
 * Design-specified accents. Both already exist as Humi tokens:
 * the indigo override dot = --color-accent-alt (#5B6CE0); the edit-mode
 * border = --color-accent (#1FA8A0). Referenced via var().
 */
export const OVERRIDE_ACCENT = 'var(--color-accent-alt)';
export const EDIT_BORDER = 'var(--color-accent)';

