/**
 * A cell is an "override" when its shift type has a default window and the
 * cell's actual times differ from that default. O/L (no default window) and
 * empty cells are never overrides.
 */
export function isOverride(cell: RosterCell | undefined | null): boolean {
  if (!cell || !cell.t) return false;
  const def = SHIFT_DEFS[cell.t];
  if (!def || !def.start) return false;
  return cell.s !== def.start || cell.e !== def.end;
}

// Roster & Shifts — TimeFirst weekly grid (ported from the Roster_TimeFirst
// design variant). Each cell shows in/out times ("time-first"); the shift type
// supplies default times and a cell that differs from default shows a blue
// override dot. Clicking a cell opens an inline editor (shift-type select + two
// time inputs). MOCKUP ONLY: Publish/Reset resolve to a transient inline toast.

'use client';

import { useMemo, useState } from 'react';
import { useLocale } from 'next-intl';
import { ChevronLeft, ChevronRight, RotateCcw, Send } from 'lucide-react';
import { cn } from '@/lib/utils';
import {
  ROSTER_TEAM,
  SHIFT_DEFS,
  DOW_LABELS,
  WEEK_RANGE,
  ROSTER_SCOPES,
  WEEKLY_TARGET,
  OVERRIDE_ACCENT,
  EDIT_BORDER,
  isOverride,
  type ShiftCode,
  type RosterCell,
  type RosterStaff,
} from '@/data/roster/mock';

type Editing = { rowId: string; dayIdx: number } | null;

export default function RosterPage() {
  const locale = useLocale();
  const isTh = locale !== 'en';

  const [team, setTeam] = useState<RosterStaff[]>(ROSTER_TEAM);
  const [editing, setEditing] = useState<Editing>(null);
  const [scope, setScope] = useState<string>(ROSTER_SCOPES[0].id);
  const [toast, setToast] = useState<string | null>(null);

  const flash = (msg: string) => {
    setToast(msg);
    window.setTimeout(() => setToast(null), 4000);
  };

  const updateCell = (rowId: string, dayIdx: number, patch: Partial<RosterCell>) => {
    setTeam((prev) =>
      prev.map((p) =>
        p.id !== rowId
          ? p
          : { ...p, days: p.days.map((d, i) => (i !== dayIdx ? d : { ...d, ...patch })) },
      ),
    );
  };

  const overrideCount = useMemo(
    () => team.reduce((sum, p) => sum + p.days.filter((d) => isOverride(d)).length, 0),
    [team],
  );

  const shiftLabel = (code: ShiftCode) =>
    isTh ? SHIFT_DEFS[code].labelTh : SHIFT_DEFS[code].labelEn;

  const handleReset = () => {
    setTeam(ROSTER_TEAM);
    setEditing(null);
    flash(isTh ? 'รีเซ็ตเป็น default ทั้งหมดแล้ว (ตัวอย่าง)' : 'Reset all to default (demo)');
  };

  const handlePublish = () =>
    flash(isTh ? 'ประกาศกะและแจ้งทีมแล้ว (ตัวอย่าง)' : 'Shifts published, team notified (demo)');

  const gridCols = '220px repeat(7, 1fr) 80px';

  return (
    <div className="pb-7 flex flex-col gap-4">
      {/* Header — eyebrow + two-tone title + subtitle, week stepper on the right */}
      <header className="flex flex-wrap items-end justify-between gap-6">
        <div className="flex flex-col gap-1">
          <span className="font-mono text-[length:var(--text-eyebrow)] font-semibold uppercase tracking-[0.14em] text-ink-faint">
            {isTh ? 'HUMI • ตารางกะ • เน้นเวลา' : 'Workforce • Schedule • time-first'}
          </span>
          <h1 className="font-display text-[length:var(--text-display-h1)] font-semibold leading-[var(--text-display-h1--line-height)] tracking-tight text-ink">
            {isTh ? (
              <>
                ตาราง<span className="italic font-medium text-accent">กะ</span> · แสดงเวลา + override
              </>
            ) : (
              <>
                Roster <span className="italic font-medium text-accent">&amp; Shifts</span>
              </>
            )}
          </h1>
          <p className="text-small text-ink-muted mt-1">
            {isTh ? (
              <>
                <b>เห็นเวลาเข้า-ออกของทุกคนพร้อมกัน</b> · ค่าตามประเภทกะเป็น default ·{' '}
                <b>คลิกที่เวลา</b> เพื่อ override สำหรับวันนั้น
              </>
            ) : (
              <>
                <b>See everyone&apos;s in/out times at once</b> · shift-type times are the default
                · <b>click a time</b> to override it for that day
              </>
            )}
          </p>
        </div>
        <div className="flex items-center gap-2">
          <button
            type="button"
            aria-label={isTh ? 'สัปดาห์ก่อนหน้า' : 'Previous week'}
            className="inline-flex h-[38px] items-center justify-center rounded-[var(--radius-md)] border border-hairline bg-surface px-3 text-ink-soft hover:bg-canvas-soft"
          >
            <ChevronLeft size={14} />
          </button>
          <span className="rounded-[var(--radius-md)] border border-hairline bg-surface px-3.5 py-2 text-small font-semibold text-ink">
            {isTh ? WEEK_RANGE.th : WEEK_RANGE.en}
          </span>
          <button
            type="button"
            aria-label={isTh ? 'สัปดาห์ถัดไป' : 'Next week'}
            className="inline-flex h-[38px] items-center justify-center rounded-[var(--radius-md)] border border-hairline bg-surface px-3 text-ink-soft hover:bg-canvas-soft"
          >
            <ChevronRight size={14} />
          </button>
        </div>
      </header>

      {/* Scope switch + override count + actions */}
      <div className="flex flex-wrap items-center gap-3">
        <div
          role="tablist"
          aria-label={isTh ? 'ขอบเขต' : 'Scope'}
          className="inline-flex gap-0 rounded-[10px] border border-hairline bg-surface p-[3px]"
        >
          {ROSTER_SCOPES.map((b) => {
            const active = scope === b.id;
            return (
              <button
                key={b.id}
                type="button"
                role="tab"
                aria-selected={active}
                onClick={() => setScope(b.id)}
                className={cn(
                  'rounded-[7px] px-3.5 py-[7px] text-xs font-semibold transition-colors',
                  active ? 'bg-accent text-white' : 'text-ink-soft hover:text-ink',
                )}
              >
                {isTh ? b.labelTh : b.labelEn}
              </button>
            );
          })}
        </div>

        <div className="flex-1" />

        {overrideCount > 0 && (
          <span
            className="inline-flex items-center gap-2 rounded-full border px-3 py-1.5 text-xs font-semibold"
            style={{
              background: 'var(--color-accent-alt-soft)',
              color: 'var(--color-accent-alt)',
              borderColor: 'var(--color-accent-alt)',
            }}
          >
            <span
              className="h-1.5 w-1.5 rounded-full"
              style={{ background: OVERRIDE_ACCENT }}
              aria-hidden
            />
            {isTh
              ? `${overrideCount} ช่อง override จาก default`
              : `${overrideCount} cells overridden from default`}
          </span>
        )}

        <button
          type="button"
          onClick={handleReset}
          className="inline-flex h-[38px] items-center gap-1.5 rounded-[var(--radius-md)] border border-hairline bg-surface px-4 text-small font-semibold text-ink-soft hover:bg-canvas-soft"
        >
          <RotateCcw size={14} />
          {isTh ? 'รีเซ็ตเป็น default ทั้งหมด' : 'Reset all to default'}
        </button>
        <button
          type="button"
          onClick={handlePublish}
          className="inline-flex h-[38px] items-center gap-1.5 rounded-[var(--radius-md)] bg-accent px-4 text-small font-semibold text-white hover:opacity-90"
        >
          <Send size={14} />
          {isTh ? 'ประกาศกะ + แจ้งทีม' : 'Publish + notify team'}
        </button>
      </div>

      {/* Transient mockup toast */}
      {toast && (
        <div
          role="status"
          className="rounded-[var(--radius-md)] border border-accent bg-accent-soft px-4 py-2.5 text-small font-medium text-accent"
        >
          {toast}
        </div>
      )}

      {/* Shift defaults legend */}
      <div className="flex flex-wrap items-center gap-3.5 rounded-[10px] border border-hairline bg-surface px-4 py-3 text-xs">
        <span className="text-xs font-bold uppercase tracking-[0.08em] text-ink-muted">
          {isTh ? 'เวลา default' : 'Default times'}
        </span>
        {(Object.entries(SHIFT_DEFS) as Array<[ShiftCode, (typeof SHIFT_DEFS)[ShiftCode]]>)
          .filter(([, s]) => s.start)
          .map(([code, s]) => (
            <span key={code} className="inline-flex items-center gap-1.5">
              <span
                className="inline-flex h-[18px] w-[18px] items-center justify-center rounded text-xs font-bold"
                style={{ background: s.bg, color: s.fg }}
              >
                {code}
              </span>
              <span className="font-semibold text-ink-soft">{shiftLabel(code)}</span>
              <span className="font-mono text-ink-muted">
                {s.start}–{s.end}
              </span>
            </span>
          ))}
        <span className="flex-1" />
        <span className="text-xs text-ink-muted">
          <span
            className="mr-1.5 inline-block h-1.5 w-1.5 rounded-full align-middle"
            style={{ background: OVERRIDE_ACCENT }}
            aria-hidden
          />
          {isTh
            ? 'จุดน้ำเงิน = override จาก default · คลิกเซลล์ใดก็ได้เพื่อแก้เวลา'
            : 'blue dot = overridden from default · click any cell to edit times'}
        </span>
      </div>

      {/* MAIN GRID */}
      <div className="overflow-hidden rounded-[var(--radius-lg)] border border-hairline bg-surface">
        {/* Column header */}
        <div
          className="grid bg-canvas-soft border-b border-hairline text-xs font-bold uppercase tracking-[0.06em] text-ink-muted"
          style={{ gridTemplateColumns: gridCols }}
        >
          <div className="px-4 py-3">{isTh ? 'พนักงาน' : 'Employee'}</div>
          {DOW_LABELS.map((d) => (
            <div key={d.en} className="border-l border-hairline-soft px-1.5 py-2.5 text-center">
              {isTh ? d.th : d.en}
            </div>
          ))}
          <div className="border-l border-hairline-soft px-2 py-3 text-center">
            {isTh ? 'ชั่วโมง' : 'Hours'}
          </div>
        </div>

        {team.map((t) => (
          <div
            key={t.id}
            className="grid border-t border-hairline-soft"
            style={{ gridTemplateColumns: gridCols }}
          >
            {/* Row label */}
            <div className="flex min-w-0 items-center gap-2.5 px-4 py-2.5">
              <div
                className={cn('humi-avatar', `humi-avatar--${t.tone}`, 'h-[30px] w-[30px] shrink-0 text-xs')}
              >
                {t.initials}
              </div>
              <div className="min-w-0 flex-1">
                <div className="truncate text-xs font-semibold text-ink">{t.name}</div>
                <div className="truncate text-xs text-ink-muted">{isTh ? t.roleTh : t.roleEn}</div>
              </div>
            </div>

            {/* Day cells */}
            {t.days.map((cell, di) => {
              const def = cell ? SHIFT_DEFS[cell.t] : null;
              const hasTime = !!def && !!def.start;
              const isEditing = editing?.rowId === t.id && editing?.dayIdx === di;
              const override = isOverride(cell);

              return (
                <div
                  key={di}
                  className="relative flex min-h-[64px] items-center justify-center border-l border-hairline-soft p-1"
                >
                  {!hasTime ? (
                    // OFF / LEAVE / empty
                    <button
                      type="button"
                      onClick={() => setEditing({ rowId: t.id, dayIdx: di })}
                      className={cn(
                        'flex h-14 w-full flex-col items-center justify-center gap-0.5 rounded-md text-xs font-bold',
                        def ? '' : 'border border-dashed border-hairline text-ink-faint',
                      )}
                      style={def ? { background: def.bg, color: def.fg } : undefined}
                    >
                      {def ? (
                        <>
                          <span>{cell.t}</span>
                          <span className="text-xs font-semibold opacity-85">
                            {shiftLabel(cell.t)}
                          </span>
                        </>
                      ) : (
                        '＋'
                      )}
                    </button>
                  ) : isEditing && def ? (
                    // Inline edit mode — shift-type select + two time inputs
                    <div
                      onBlur={(e) => {
                        if (!e.currentTarget.contains(e.relatedTarget as Node)) setEditing(null);
                      }}
                      className="flex h-14 w-full flex-col gap-0.5 rounded-md p-1"
                      style={{ background: def.bg, color: def.fg, border: `2px solid ${EDIT_BORDER}` }}
                    >
                      <select
                        value={cell.t}
                        autoFocus
                        aria-label={isTh ? 'ประเภทกะ' : 'Shift type'}
                        onChange={(e) => {
                          const newType = e.target.value as ShiftCode;
                          const d = SHIFT_DEFS[newType];
                          updateCell(t.id, di, { t: newType, s: d.start, e: d.end });
                        }}
                        className="rounded-[3px] border-0 px-1 py-px text-center font-display text-xs font-bold"
                        style={{ background: 'var(--color-surface)', color: def.fg }}
                      >
                        {(Object.keys(SHIFT_DEFS) as ShiftCode[]).map((code) => (
                          <option key={code} value={code}>
                            {code} · {shiftLabel(code)}
                          </option>
                        ))}
                      </select>
                      <div className="flex items-center gap-0.5">
                        <input
                          type="time"
                          value={cell.s ?? ''}
                          aria-label={isTh ? 'เวลาเข้า' : 'Start time'}
                          onChange={(e) => updateCell(t.id, di, { s: e.target.value })}
                          className="w-0 min-w-0 flex-1 rounded-[3px] border-0 bg-white px-[3px] py-0.5 font-mono text-xs font-bold"
                          style={{ color: def.fg }}
                        />
                        <span className="text-xs opacity-60" style={{ color: def.fg }}>
                          –
                        </span>
                        <input
                          type="time"
                          value={cell.e ?? ''}
                          aria-label={isTh ? 'เวลาออก' : 'End time'}
                          onChange={(e) => updateCell(t.id, di, { e: e.target.value })}
                          className="w-0 min-w-0 flex-1 rounded-[3px] border-0 bg-white px-[3px] py-0.5 font-mono text-xs font-bold"
                          style={{ color: def.fg }}
                        />
                      </div>
                    </div>
                  ) : (
                    // Default display — time-first
                    <button
                      type="button"
                      onClick={() => setEditing({ rowId: t.id, dayIdx: di })}
                      className="relative flex h-14 w-full flex-col items-center justify-center gap-0.5 rounded-md border-0 px-1.5 py-1"
                      style={{ background: def!.bg, color: def!.fg }}
                    >
                      <span className="font-mono text-small font-bold leading-tight tracking-[-0.01em]">
                        {cell.s}
                      </span>
                      <span className="font-mono text-xs font-semibold leading-tight opacity-70">
                        {cell.e}
                      </span>
                      {override && (
                        <span
                          className="absolute right-1 top-1 h-1.5 w-1.5 rounded-full"
                          style={{
                            background: OVERRIDE_ACCENT,
                            boxShadow: '0 0 0 1.5px var(--color-surface)',
                          }}
                          title={isTh ? 'Override จาก default' : 'Overridden from default'}
                        />
                      )}
                    </button>
                  )}
                </div>
              );
            })}

            {/* Hours column */}
            <div className="flex flex-col items-center justify-center border-l border-hairline-soft px-2 py-2.5 text-center">
              <span className="font-display text-base font-bold text-ink">{t.hours}</span>
              <span className="text-xs text-ink-muted">
                {isTh ? `ของ ${WEEKLY_TARGET}` : `of ${WEEKLY_TARGET}`}
              </span>
            </div>
          </div>
        ))}
      </div>

      {/* Helper note (indigo callout) */}
      <div
        className="flex items-center gap-3 rounded-[10px] px-4 py-3 text-xs"
        style={{
          background: 'var(--color-accent-alt-soft)',
          borderLeft: `3px solid ${OVERRIDE_ACCENT}`,
          color: 'var(--color-ink)',
        }}
      >
        <span
          className="rounded-full px-2 py-0.5 text-xs font-bold tracking-[0.08em] text-white"
          style={{ background: OVERRIDE_ACCENT }}
        >
          {isTh ? 'วิธี' : 'HOW'}
        </span>
        <span>
          {isTh ? (
            <>
              <b>คลิกเซลล์</b> เพื่อเปลี่ยนประเภทกะ (M/A/N/O/L) ทันที + แก้เวลาเข้า/ออก ·
              ค่าจาก default ใช้แทนได้ทันที · เวลาที่ override จะมี{' '}
              <b style={{ color: OVERRIDE_ACCENT }}>จุดน้ำเงิน</b> ที่มุมเซลล์
            </>
          ) : (
            <>
              <b>Click a cell</b> to change shift type (M/A/N/O/L) instantly and edit in/out times ·
              defaults apply automatically · overridden times show a{' '}
              <b style={{ color: OVERRIDE_ACCENT }}>blue dot</b> in the cell corner
            </>
          )}
        </span>
      </div>
    </div>
  );
}

