    roleTh: 'บาริสต้า',
    roleEn: 'Barista',
    location: 'FOH',
    targetHours: 9, // under target (8.0h) -> renders pumpkin
    shifts: [shift('s-5a', 'regular', 6, 14, 10, 11)],
  },
  {
    id: 'row-6',
