// Displayed hours follow the reference: the cell + TOTAL show the GROSS shift
// span (end − start). Breaks are shown only as the hatch overlay, not deducted
// from the number (matches the ref's 9.0/9.0/4.0/9.0/8.0/7.0 per-row figures).
/** Gross hours for a shift (end − start). */
export function shiftHours(s: RosterShift): number {
  return s.end - s.start;
}

/** Total gross hours across a row's shifts. */
export function rowTotalHours(row: RosterRow): number {
  return row.shifts.reduce((n, s) => n + shiftHours(s), 0);
}

// 24-hour coverage row tuned to the reference summary: 12 gaps, peak 13–16,
// deficit −16 hrs. ok = adequately staffed, over = peak overlap, gap =
// understaffed against demand, off = no demand / closed.
export const COVERAGE: CoverageStatus[] = [
  'off', 'off', 'off', 'off', 'off', 'off', // 00–05 closed
  'gap', 'gap', 'gap', 'ok', 'ok', 'ok',    // 06–11 ramp, early gaps
  'gap', 'over', 'over', 'over', 'over', 'ok', // 12–17 afternoon peak 13–16
  'gap', 'gap', 'gap', 'gap', 'gap', 'gap', // 18–23 evening understaffed
];

/** Coverage summary shown in the strip label + total slot. */
export const COVERAGE_SUMMARY = {
  gaps: 12,
  peakStart: 13,
  peakEnd: 16,
  deficitHrs: -16,
};

/** Avatar background tokens (teal/indigo/pumpkin family — NO hex, NO red). */
export const AVATAR_BG: Record<string, string> = {
  'row-1': 'bg-accent',
  'row-2': 'bg-[var(--color-accent-alt)]',
  'row-3': 'bg-danger',
  'row-4': 'bg-[var(--color-accent-alt)]',
  'row-5': 'bg-accent',
  'row-6': 'bg-[var(--color-ink-soft)]',
};

// RosterGantt — employee rows × 24 hour columns, with a TOTAL column.
// Faithful to roster-ref-2026-05-25.png:
//   grid = [240px employee][76px total][repeat(24,1fr) hours]
//   shift cell shows the TIME RANGE (left, mono) + DURATION (right, dimmed);
//   shift TYPE is conveyed by COLOR only (no type-name text).
//   break window = diagonal-hatch overlay; NOW = thin pumpkin vertical line.
// Tokens only: NO hardcoded hex, NO Tailwind red/rose/pink (danger = pumpkin),
// text sizes via the Tailwind scale (Humi R4 contract — no arbitrary px text).

'use client';

import { useLocale } from 'next-intl';
import { cn } from '@/lib/utils';
import {
  ROSTER_HOURS,
  NOW_HOUR,
  NOW_MINUTE,
  AVATAR_BG,
  rowTotalHours,
  shiftHours,
  type RosterRow,
  type RosterShift,
  type ShiftType,
} from '@/data/roster/mock';

// Shift archetype -> tokenized class set (AC1.2 / AC1.8 mapping):
//   manager  indigo -> accent-alt-soft bg + accent-alt border
//   partTime amber  -> warning-soft bg + warning border  (NEVER bg-warning-tint)
//   night    navy   -> ink bg + LIGHT canvas-soft text (NOT text-ink)
//   regular  teal   -> accent-soft bg + accent text + accent border
export const SHIFT_TYPE_CLASS: Record<ShiftType, string> = {
  manager:
    'bg-[var(--color-accent-alt-soft)] border-[var(--color-accent-alt)] text-ink',
  partTime: 'bg-warning-soft border-warning text-ink',
  night: 'bg-[var(--color-ink)] text-[var(--color-canvas-soft)] border-[var(--color-ink)]',
  regular: 'bg-accent-soft text-accent border-accent',
};

const GRID_COLS = `240px 76px repeat(${ROSTER_HOURS}, minmax(0,1fr))`;

function pct(hour: number): number {
  return (hour / ROSTER_HOURS) * 100;
}

function fmtHour(h: number): string {
  return `${Math.floor(h).toString().padStart(2, '0')}:00`;
}

function fmtHours(n: number): string {
  return `${n.toFixed(1)}h`;
}

export interface RosterGanttProps {
  rows: RosterRow[];
  onShiftClick?: (shift: RosterShift, row: RosterRow) => void;
}

export function RosterGantt({ rows, onShiftClick }: RosterGanttProps) {
  const locale = useLocale();
  const isTh = locale !== 'en';
  // Hour axis labels 01..24 (ref style), one per column.
  const hourLabels = Array.from({ length: ROSTER_HOURS }, (_, i) => i + 1);
  const nowLeft = ((NOW_HOUR + NOW_MINUTE / 60) / ROSTER_HOURS) * 100;

  return (
    <div data-testid="roster-gantt" className="overflow-x-auto">
      <div className="min-w-[980px]">
        {/* Hour header */}
        <div
          className="grid items-center border-b border-hairline"
          style={{ gridTemplateColumns: GRID_COLS }}
          role="row"
        >
          <div className="px-4 py-2.5 font-mono text-[length:var(--text-eyebrow)] font-semibold uppercase tracking-[0.1em] text-ink-faint">
            {isTh ? 'พนักงาน' : 'Employee'}
          </div>
          <div className="px-2 py-2.5 font-mono text-[length:var(--text-eyebrow)] font-semibold uppercase tracking-[0.1em] text-ink-faint">
            {isTh ? 'รวม' : 'Total'}
          </div>
          {hourLabels.map((h) => (
            <div
              key={h}
              data-testid="hour-col"
              className="border-l border-hairline-soft py-2.5 text-center font-mono text-[length:var(--text-eyebrow)] font-semibold text-ink-faint"
            >
              {h.toString().padStart(2, '0')}
            </div>
          ))}
        </div>

        {/* Rows + a single NOW line overlay spanning all rows */}
        <div className="relative">
          {/* NOW line — thin pumpkin vertical marker with a dot at the top */}
          <div
            data-testid="now-line"
            aria-hidden
            className="pointer-events-none absolute top-0 bottom-0 z-20 w-px bg-danger"
            style={{
              // offset into the hours track: 240 + 76 = 316px label columns,
              // then nowLeft% of the remaining width.
              left: `calc(316px + (100% - 316px) * ${nowLeft / 100})`,
            }}
          >
            <span className="absolute -left-[3px] -top-[3px] h-2 w-2 rounded-full bg-danger" />
          </div>

          {rows.map((row) => {
            const total = rowTotalHours(row);
            const under = total < row.targetHours;
            return (
              <div
                key={row.id}
                data-testid="roster-row"
                className="grid items-stretch border-b border-hairline-soft"
                style={{ gridTemplateColumns: GRID_COLS }}
                role="row"
              >
                {/* Employee cell — avatar + name + mono meta line */}
                <div className="flex items-center gap-3 px-4 py-3.5">
                  <span
                    className={cn(
                      'inline-flex h-[30px] w-[30px] shrink-0 items-center justify-center rounded-full text-xs font-bold text-white',
                      AVATAR_BG[row.id] ?? 'bg-accent',
                    )}
                    aria-hidden
                  >
                    {row.initials}
                  </span>
                  <span className="flex min-w-0 flex-col">
                    <span className="truncate font-display text-base font-semibold leading-tight tracking-tight text-ink">
                      {row.name}
                    </span>
                    <span className="mt-0.5 truncate font-mono text-xs uppercase tracking-[0.02em] text-ink-muted">
                      {row.employmentType} · {isTh ? row.roleTh : row.roleEn} ·{' '}
                      {row.location}
                    </span>
                  </span>
                </div>

                {/* TOTAL cell — pumpkin when under target */}
                <div className="flex items-center px-2 py-3.5">
                  <span
                    data-testid="total-cell"
                    data-under={under ? 'true' : 'false'}
                    className={cn(
                      'font-mono text-sm font-bold tracking-[0.02em]',
                      under ? 'text-danger' : 'text-ink',
                    )}
                  >
                    {fmtHours(total)}
                  </span>
                </div>

                {/* Shift track — spans all 24 hour columns */}
                <div
                  data-testid="shift-track"
                  className="relative min-h-[58px]"
                  style={{ gridColumn: `3 / span ${ROSTER_HOURS}` }}
                >
                  {/* faint hour gridlines */}
                  <div
                    aria-hidden
                    className="pointer-events-none absolute inset-0 grid"
                    style={{ gridTemplateColumns: `repeat(${ROSTER_HOURS}, minmax(0,1fr))` }}
                  >
                    {Array.from({ length: ROSTER_HOURS }, (_, i) => (
                      <span key={i} className="border-l border-hairline-soft first:border-l-0" />
                    ))}
                  </div>

                  {row.shifts.map((s) => {
                    const left = pct(s.start);
                    const width = pct(s.end - s.start);
                    const dur = shiftHours(s);
                    const hasBreak = s.breakStart != null && s.breakEnd != null;
                    // break position relative to the shift cell width
                    const span = s.end - s.start;
                    const brkLeft = hasBreak ? ((s.breakStart! - s.start) / span) * 100 : 0;
                    const brkWidth = hasBreak
                      ? ((s.breakEnd! - s.breakStart!) / span) * 100
                      : 0;
                    return (
                      <button
                        key={s.id}
                        type="button"
                        data-testid="shift-cell"
                        data-shift-type={s.type}
                        onClick={() => onShiftClick?.(s, row)}
                        title={`${fmtHour(s.start)} – ${fmtHour(s.end)} · ${fmtHours(dur)}`}
                        aria-label={`${row.name} ${fmtHour(s.start)}–${fmtHour(s.end)} ${fmtHours(dur)}`}
                        className={cn(
                          'absolute top-[11px] bottom-[11px] z-10 overflow-hidden rounded-[7px] border px-2.5',
                          'flex items-center justify-between font-mono text-xs font-semibold tracking-[0.02em]',
                          'shadow-[var(--shadow-sm)] transition-[filter] hover:brightness-[0.97]',
                          'focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent focus-visible:ring-offset-1',
                          SHIFT_TYPE_CLASS[s.type],
                        )}
                        style={{ left: `${left}%`, width: `calc(${width}% - 4px)` }}
                      >
                        {/* break stripe — tokenized diagonal hatch (no hex) */}
                        {hasBreak && (
                          <span
                            data-testid="break-stripe"
                            aria-hidden
                            className="pointer-events-none absolute top-[3px] bottom-[3px] rounded-[4px] [background:repeating-linear-gradient(45deg,color-mix(in_oklab,currentColor_55%,transparent)_0_3px,transparent_3px_6px)]"
                            style={{ left: `${brkLeft}%`, width: `${brkWidth}%` }}
                          />
                        )}
                        <span className="relative z-10 truncate">
                          {fmtHour(s.start)} – {fmtHour(s.end)}
                        </span>
                        <span className="relative z-10 ml-2 shrink-0 font-medium opacity-65">
                          {fmtHours(dur)}
                        </span>
                      </button>
                    );
                  })}
                </div>
              </div>
            );
          })}
        </div>
      </div>
    </div>
  );
}

// CoverageStrip — coverage row sibling to RosterGantt. Matches the reference:
//   [240px label][76px deficit][24 coverage cells] grid.
//   label = "COVERAGE" eyebrow + summary "12 gaps · Peak 13–16".
//   deficit slot = "−16 hrs" in pumpkin (text-danger, no bg).
//   cells: ok=bg-accent, gap=bg-danger (pumpkin), over=accent-alt opacity-60,
//   off=bg-hairline thin (4px). Tokens only — NO hex, NO Tailwind red.

'use client';

import { useLocale } from 'next-intl';
import { cn } from '@/lib/utils';
import {
  COVERAGE,
  COVERAGE_SUMMARY,
  ROSTER_HOURS,
  type CoverageStatus,
} from '@/data/roster/mock';

// status -> token class (ref .cov-cell map; gap = pumpkin = --color-danger).
const COV_CELL_CLASS: Record<CoverageStatus, string> = {
  ok: 'bg-accent',
  gap: 'bg-danger',
  over: 'bg-[var(--color-accent-alt)] opacity-60',
  off: 'bg-hairline',
};

const COV_LABEL: Record<CoverageStatus, { th: string; en: string }> = {
  ok: { th: 'พอเพียง', en: 'Covered' },
  gap: { th: 'ขาดคน', en: 'Gap' },
  over: { th: 'เกินจำเป็น', en: 'Over' },
  off: { th: 'ปิดกะ', en: 'Off' },
};

const GRID_COLS = `240px 76px repeat(${ROSTER_HOURS}, minmax(0,1fr))`;

export function CoverageStrip({ coverage = COVERAGE }: { coverage?: CoverageStatus[] }) {
  const locale = useLocale();
  const isTh = locale !== 'en';
  const { gaps, peakStart, peakEnd, deficitHrs } = COVERAGE_SUMMARY;

  const summary = isTh
    ? `${gaps} ช่องว่าง · พีค ${peakStart}–${peakEnd}`
    : `${gaps} gaps · Peak ${peakStart}–${peakEnd}`;

  return (
    <div
      data-testid="coverage-strip"
      className="grid items-stretch bg-canvas-soft"
      style={{ gridTemplateColumns: GRID_COLS }}
      role="row"
      aria-label={isTh ? 'ความครอบคลุมกะรายชั่วโมง' : 'Hourly shift coverage'}
    >
      {/* Label column */}
      <div className="flex flex-col justify-center gap-1 px-4 py-3.5">
        <span className="font-mono text-[length:var(--text-eyebrow)] font-bold uppercase tracking-[0.14em] text-ink-faint">
          {isTh ? 'ความครอบคลุม' : 'Coverage'}
        </span>
        <span
          data-testid="coverage-summary"
          className="font-display text-sm tracking-tight text-ink-soft"
        >
          {summary}
        </span>
      </div>

      {/* Deficit slot (aligns with the gantt TOTAL column) */}
      <div className="flex items-center gap-1 px-2 py-3.5">
        <span data-testid="coverage-deficit" className="font-mono font-bold text-danger">
          {deficitHrs} {isTh ? 'ชม.' : 'hrs'}
        </span>
      </div>

      {/* 24 coverage cells */}
      <div
        className="grid items-center gap-0.5 border-l border-hairline-soft py-3.5"
        style={{
          gridColumn: `3 / span ${ROSTER_HOURS}`,
          gridTemplateColumns: `repeat(${ROSTER_HOURS}, minmax(0,1fr))`,
        }}
      >
        {coverage.slice(0, ROSTER_HOURS).map((status, hour) => {
          const lbl = COV_LABEL[status];
          return (
            <div
              key={hour}
              data-testid="cov-cell"
              data-status={status}
              title={`${hour.toString().padStart(2, '0')}:00 · ${isTh ? lbl.th : lbl.en}`}
              aria-label={`${hour.toString().padStart(2, '0')}:00 ${isTh ? lbl.th : lbl.en}`}
              className={cn(
                'rounded',
                // off is a thin hairline rule; the rest fill the row height
                status === 'off' ? 'h-1' : 'h-[18px]',
                COV_CELL_CLASS[status],
              )}
            />
          );
        })}
      </div>
    </div>
  );
}

// ShiftEditorDrawer — right-side drawer opened on shift-cell click.
// Prefilled from the clicked shift (local state only). Save = onSave + close
// (parent fires a toast). No persistence, no API — MOCKUP ONLY.

'use client';

import { useEffect, useState } from 'react';
import { createPortal } from 'react-dom';
import { useLocale } from 'next-intl';
import { X } from 'lucide-react';
import { Button } from '@/components/humi';
import { cn } from '@/lib/utils';
import {
  SHIFT_TYPE_LABELS,
  type RosterShift,
  type ShiftType,
} from '@/data/roster/mock';

const SHIFT_TYPES: ShiftType[] = ['manager', 'partTime', 'night', 'regular'];

export interface ShiftEditorDrawerProps {
  open: boolean;
  shift: RosterShift | null;
  employeeName?: string;
  onClose: () => void;
  onSave: (draft: { type: ShiftType; start: number; end: number }) => void;
}

export function ShiftEditorDrawer({
  open,
  shift,
  employeeName,
  onClose,
  onSave,
}: ShiftEditorDrawerProps) {
  const locale = useLocale();
  const isTh = locale !== 'en';

  const [type, setType] = useState<ShiftType>('regular');
  const [start, setStart] = useState(9);
  const [end, setEnd] = useState(18);

  // Prefill from the clicked shift each time the drawer opens.
  useEffect(() => {
    if (open && shift) {
      setType(shift.type);
      setStart(shift.start);
      setEnd(shift.end);
    }
  }, [open, shift]);

  // Close on Escape.
  useEffect(() => {
    if (!open) return;
    const handler = (e: KeyboardEvent) => {
      if (e.key === 'Escape') onClose();
    };
    document.addEventListener('keydown', handler);
    return () => document.removeEventListener('keydown', handler);
  }, [open, onClose]);

  if (!open) return null;

  return createPortal(
    <div
      role="dialog"
      aria-modal="true"
      aria-label={isTh ? 'แก้ไขกะ' : 'Edit shift'}
      className="fixed inset-0 z-50 flex justify-end bg-ink/40 backdrop-blur-sm"
      onClick={(e) => {
        if (e.target === e.currentTarget) onClose();
      }}
    >
      <div
        data-testid="shift-editor-drawer"
        className={cn(
          'flex h-full w-full max-w-md flex-col bg-surface shadow-[var(--shadow-lg)]',
          'border-l border-hairline',
        )}
      >
        {/* Header */}
        <div className="flex items-center justify-between gap-3 border-b border-hairline px-6 py-4">
          <h2 className="font-display text-[length:var(--text-display-h3)] font-semibold tracking-tight text-ink">
            {isTh ? 'แก้ไขกะ' : 'Edit shift'}
          </h2>
          <button
            type="button"
            aria-label={isTh ? 'ปิด' : 'Close'}
            onClick={onClose}
            className="inline-flex h-10 w-10 items-center justify-center rounded-full text-ink-muted transition-colors hover:bg-canvas-soft hover:text-ink"
          >
            <X size={16} aria-hidden />
          </button>
        </div>

        {/* Body */}
        <div className="min-h-0 flex-1 overflow-y-auto px-6 py-5">
          {employeeName && (
            <p className="mb-4 text-small text-ink-muted">
              {isTh ? 'พนักงาน' : 'Employee'}:{' '}
              <span className="font-medium text-ink">{employeeName}</span>
            </p>
          )}

          {/* Shift type */}
          <label className="mb-1.5 block text-small font-medium text-ink-soft">
            {isTh ? 'ประเภทกะ' : 'Shift type'}
          </label>
          <div className="mb-5 grid grid-cols-2 gap-2">
            {SHIFT_TYPES.map((t) => (
              <button
                key={t}
                type="button"
                data-testid={`type-${t}`}
                aria-pressed={type === t}
                onClick={() => setType(t)}
                className={cn(
                  'rounded-md border px-3 py-2 text-small font-medium transition-colors',
                  type === t
                    ? 'border-accent bg-accent-soft text-accent'
                    : 'border-hairline bg-surface text-ink-soft hover:bg-canvas-soft',
                )}
              >
                {isTh ? SHIFT_TYPE_LABELS[t].th : SHIFT_TYPE_LABELS[t].en}
              </button>
            ))}
          </div>

          {/* Start / End */}
          <div className="grid grid-cols-2 gap-3">
            <div className="flex flex-col gap-1.5">
              <label className="text-small font-medium text-ink-soft">
                {isTh ? 'เริ่ม (ชม.)' : 'Start (hr)'}
              </label>
              <input
                type="number"
                min={0}
                max={23}
                value={start}
                onChange={(e) => setStart(Number(e.target.value))}
                className="w-full rounded-[var(--radius-md)] border border-hairline bg-surface px-3 py-2.5 text-body text-ink focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent focus-visible:ring-offset-2"
              />
            </div>
            <div className="flex flex-col gap-1.5">
              <label className="text-small font-medium text-ink-soft">
                {isTh ? 'สิ้นสุด (ชม.)' : 'End (hr)'}
              </label>
              <input
                type="number"
                min={1}
                max={24}
                value={end}
                onChange={(e) => setEnd(Number(e.target.value))}
                className="w-full rounded-[var(--radius-md)] border border-hairline bg-surface px-3 py-2.5 text-body text-ink focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-accent focus-visible:ring-offset-2"
              />
            </div>
          </div>
        </div>

        {/* Footer */}
        <div className="flex items-center justify-end gap-3 border-t border-hairline px-6 py-4">
          <Button variant="ghost" onClick={onClose}>
            {isTh ? 'ยกเลิก' : 'Cancel'}
          </Button>
          <Button variant="primary" onClick={() => onSave({ type, start, end })}>
            {isTh ? 'บันทึก' : 'Save'}
          </Button>
        </div>
      </div>
    </div>,
    document.body,
  );
}

// ShiftSwapModal — request to swap a shift between two employees.
