          </select>
        </div>

        <div className="flex flex-col gap-1.5">
          <label className="text-small font-medium text-ink-soft">
            {isTh ? 'ไปยังพนักงาน' : 'To employee'}
          </label>
          <select
            value={to}
            onChange={(e) => setTo(e.target.value)}
